local function s2(hD, dG)
	if typeof(hD) ~= typeof(dG) then
		local oq = ("{1} is of type %s, but {2} is of type %s"):format(typeof(hD), typeof(dG))
		return false, oq
	end
	if typeof(hD) == "table" then
		local s3 = {}
		for ej, d3 in pairs(hD) do
			s3[ej] = true
			local nr, s4 = s2(d3, dG[ej])
			if not nr then
				local oq = s4:gsub("{1}", ("{1}[%s]"):format(tostring(ej)))
					:gsub("{2}", ("{2}[%s]"):format(tostring(ej)))
				return false, oq
			end
		end
		for ej, d3 in pairs(dG) do
			if not s3[ej] then
				local nr, s4 = s2(d3, hD[ej])
				if not nr then
					local oq = s4:gsub("{1}", ("{1}[%s]"):format(tostring(ej)))
						:gsub("{2}", ("{2}[%s]"):format(tostring(ej)))
					return false, oq
				end
			end
		end
		return true
	end
	if hD == dG then
		return true
	end
	local oq = "{1} ~= {2}"
	return false, oq
end
local function s5(hD, dG)
	local nr, s6 = s2(hD, dG)
	if not nr then
		local s4 = s6:gsub("{1}", "first"):gsub("{2}", "second")
		local oq = ("Values were not deep-equal.\n%s"):format(s4)
		error(oq, 2)
	end
end
return s5
